import openpyxl
import os
import unicodedata

def normalize\(s\):
    if s is None:
        return ""
    s = str\(s\).strip\(\).lower\(\)
    s = s.replace\("'", ""\).replace\("_", " "\)
    s = unicodedata.normalize\("NFKD", s\)
    s = "".join\(c for c in s if not unicodedata.combining\(c\)\)
    s = " ".join\(s.split\(\)\)
    return s

def normalize_model\(val\):
    if val is None:
        return ""
    s = str\(val\).strip\(\)
    try:
        f = float\(s\)
        if f == int\(f\):
            s = str\(int\(f\)\)
    except ValueError:
        pass
    return s

MEKS_ROOT = r"D:\\MegaMek Projects\\mm-data\\data\\mekfiles\\meks"

# Step 1: Build MTF index
print\("Scanning MTF files..."\)
mtf_index = {}

for root, dirs, files in os.walk\(MEKS_ROOT\):
    for f in files:
        if not f.endswith\(".mtf"\):
            continue
        fp = os.path.join\(root, f\)
        chassis = ""
        clanname = ""
        model = ""
        era = ""
        try:
            with open\(fp, "r", encoding="utf-8", errors="replace"\) as fh:
                for line_num, line in enumerate\(fh, 1\):
                    ls = line.strip\(\)
                    if ls.startswith\("chassis:"\):
                        chassis = ls.split\(":", 1\)[1].strip\(\)
                    elif ls.startswith\("clanname:"\):
                        clanname = ls.split\(":", 1\)[1].strip\(\)
                    elif ls.startswith\("model:"\):
                        model = ls.split\(":", 1\)[1].strip\(\)
                    elif ls.startswith\("Era:"\):
                        era = ls.split\(":", 1\)[1].strip\(\)
                    if line_num >= 30:
                        break
        except:
            continue

        key = \(normalize\(chassis\), normalize\(model\)\)
        if key not in mtf_index:
            mtf_index[key] = []
        mtf_index[key].append\(\(fp, era\)\)

        if clanname:
            combined = f"{chassis} \({clanname}\)"
            key2 = \(normalize\(combined\), normalize\(model\)\)
            if key2 not in mtf_index:
                mtf_index[key2] = []
            mtf_index[key2].append\(\(fp, era\)\)

print\(f"  Indexed {len\(mtf_index\)} keys"\)

# Step 2: Read Date Proposals and collect updates
print\("\\nReading Date Proposals..."\)
dp_fp = r"F:\\Dropbox\\MegaMek Stuff\\01 - Data for MM\\Fluff Sheets\\3025C Date Proposals.xlsx"
