ws_dp = dp_wb.active

updates = []

for i, row in enumerate\(ws_dp.iter_rows\(min_row=1, values_only=True\)\):
    if i == 0:
        continue
    chassis = str\(row[0]\).strip\(\) if row[0] else ""
    model = normalize_model\(row[1]\) if row[1] else ""
    new_date = str\(int\(row[4]\)\) if row[4] else ""

    if not chassis or not new_date:
        continue

    try:
        new_date = str\(int\(float\(new_date\)\)\)
    except:
        pass

    key = \(normalize\(chassis\), normalize\(model\)\)
    mtf_entries = mtf_index.get\(key, []\)

    for fp, current_era in mtf_entries:
        if current_era != new_date:
            updates.append\(\(fp, current_era, new_date, chassis, model\)\)

dp_wb.close\(\)

# Step 3: Apply updates
print\(f"\\nApplying {len\(updates\)} Era date updates..."\)
applied = 0
errors = 0

for fp, old_era, new_era, chassis, model in updates:
    try:
        with open\(fp, "r", encoding="utf-8", errors="replace"\) as fh:
            lines = fh.readlines\(\)

        found = False
        for j, line in enumerate\(lines\):
