        if not found:
            # Insert after TechBase: line
            for j, line in enumerate\(lines\):
                if line.strip\(\).startswith\("TechBase:"\):
                    lines.insert\(j + 1, f"Era:{new_era}\\n"\)
                    found = True
                    break

        if found:
